// Process refund or order status check
const requestType = $json.request_type;
const customerData = $json.customerData;

if (requestType === 'refund') {
  // Check refund eligibility
  return {
    eligible: customerData.orderDate > new Date(Date.now() - 30*24*60*60*1000),
    amount: customerData.orderAmount
  };
} else if (requestType === 'order_status') {
  // Fetch order status from database
  return {
    orderId: customerData.orderId,
    status: 'shipped',
    trackingNumber: customerData.trackingNumber
  };
}

return { processed: true };

