[Signature Lines]
`;

return {
  contractText: contractTemplate,
  contractNumber: `CONTRACT-${Date.now()}`,
  customerName: opportunity.customerName,
  amount: opportunity.amount,
  term: opportunity.term
};

// Extract domain and verify
const email = $json.email;
const domain = email.split('@')[1];
const companyDomain = $json.companyDomain;

return {
  emailDomain: domain,
  domainVerified: domain === companyDomain,
  portalUsername: email,
  portalPassword: generatePassword(), // In production, use secure password generation
  accountCreated: true
};

function generatePassword() {
  return Math.random().toString(36).slice(-12);
}

